param(
 [Parameter(Mandatory=$true)][ValidateSet('preflight','prepare','launch','status','package','record-import','harden-acl','recover-acl','cache-preflight-prepare','cache-preflight-contain','cache-preflight-launch','cache-preflight-cleanup','canary-prepare','canary-launch','terminate-bound-canary','finalize-canary','classify-stale','classify-incomplete','cleanup-incomplete','detached-bootstrap','detached-workload')][string]$Mode,
 [string]$RunId,
 [string]$IncomingRoot,
 [ValidateSet('GDAXI','AUDCAD')][string]$Symbol,
 [long]$BeforeBarCount,
 [long]$AfterBarCount,
 [string]$BeforeEarliest,
 [string]$BeforeLatest,
 [string]$AfterEarliest,
 [string]$AfterLatest,
 [string]$EvaluationPath,
 [string]$ImportRecordPath,
 [string]$AuditId,
 [string]$ExpectedToolSha256,
 [ValidateSet('success','intentional-failure','parameter-failure','disconnect','forced-termination')][string]$CanaryKind,
 [string]$EnvelopePath,
 [string]$LauncherName,
 [string]$LauncherSid,
 [string]$WorkloadPath,
 [string]$WorkloadSha256,
 [string]$ConfigurationPath,
 [string]$ConfigurationSha256,
 [string]$WorkingDirectory,
 [string]$StdoutPath,
 [string]$StderrPath,
 [string]$ForensicCapturePath,
 [string]$RootCausePath,
 [string]$EvidenceRoot='C:\NoraEvidence\Phase2'
)
$ErrorActionPreference='Stop'
$schema='nora.phase2_persistent_evidence_runner_v1'
$terminal='C:\Program Files\Darwinex MetaTrader 5\terminal64.exe'
$required=@('SYSTEM','BA','')

function Hash([string]$Path){(Get-FileHash -Algorithm SHA256 -LiteralPath $Path).Hash.ToLowerInvariant()}
function BytesHash([byte[]]$Bytes){([Security.Cryptography.SHA256]::Create().ComputeHash($Bytes)|ForEach-Object {$_.ToString('x2')}) -join ''}
function AtomicJson([string]$Path,$Value){$tmp=$Path+'.partial.'+[guid]::NewGuid().ToString('N');$Value|ConvertTo-Json -Depth 12 -Compress|Set-Content -LiteralPath $tmp -Encoding utf8 -NoNewline;if(Test-Path -LiteralPath $Path){$backup=$Path+'.replace-backup.'+[guid]::NewGuid().ToString('N');[IO.File]::Replace($tmp,$Path,$backup);Remove-Item -LiteralPath $backup -Force}else{[IO.File]::Move($tmp,$Path)}}
function NormalizePath([string]$Path){$Path.TrimStart('\').Replace('\','/')}
function NeedRunId(){if(!$RunId -or $RunId -notmatch '^[A-Za-z0-9][A-Za-z0-9._-]{2,127}$'){throw 'invalid run identity'}}
function Paths(){NeedRunId;return [ordered]@{incoming=(Join-Path $EvidenceRoot ('incoming\'+$RunId));running=(Join-Path $EvidenceRoot ('runs\'+$RunId+'.running'));complete=(Join-Path $EvidenceRoot ('runs\'+$RunId+'.complete'));returned=(Join-Path $EvidenceRoot ('returned\'+$RunId+'.published'));job=(Join-Path $EvidenceRoot ('jobs\'+$RunId+'.json'));stdout=(Join-Path $EvidenceRoot ('logs\'+$RunId+'.stdout.log'));stderr=(Join-Path $EvidenceRoot ('logs\'+$RunId+'.stderr.log'))}}
function Inventory([string]$Base){@(Get-ChildItem -LiteralPath $Base -File -Recurse -Force|Sort-Object FullName|ForEach-Object{[ordered]@{path=NormalizePath ($_.FullName.Substring($Base.Length));size=[int64]$_.Length;sha256=Hash $_.FullName}})}
function CurrentInventory([string]$Base){@(Get-ChildItem -LiteralPath $Base -Force -Recurse|Sort-Object FullName|ForEach-Object{[ordered]@{path=NormalizePath ($_.FullName.Substring($Base.Length));type=if($_.PSIsContainer){'directory'}else{'file'};reparse=(($_.Attributes -band [IO.FileAttributes]::ReparsePoint) -ne 0);size=if($_.PSIsContainer){$null}else{[int64]$_.Length};sha256=if($_.PSIsContainer){$null}else{Hash $_.FullName}}})}
function Identity(){ $i=[Security.Principal.WindowsIdentity]::GetCurrent();[ordered]@{name=$i.Name;sid=$i.User.Value} }
function AclView([string]$Path){$a=Get-Acl -LiteralPath $Path;[ordered]@{owner=$a.Owner;sddl=$a.Sddl;protected=$a.AreAccessRulesProtected;access=@($a.Access|ForEach-Object{[ordered]@{identity=$_.IdentityReference.Value;rights=[string]$_.FileSystemRights;type=[string]$_.AccessControlType;inherited=$_.IsInherited}})}}
function RuleSid($Rule){try{return $Rule.IdentityReference.Translate([Security.Principal.SecurityIdentifier]).Value}catch{throw 'unresolvable ACL principal'}}
function AssertSecureAcl([string]$Path,[bool]$RequireProtected=$false){$a=Get-Acl -LiteralPath $Path;if($RequireProtected -and !$a.AreAccessRulesProtected){throw 'evidence root ACL inheritance enabled'};$broad='S-1-1-0','S-1-5-11','S-1-5-32-545';foreach($rule in @($a.Access)){if(($broad -contains (RuleSid $rule)) -and ([string]$rule.FileSystemRights -match 'Write|Modify|FullControl|Delete')){throw 'broad evidence write ACL'}}}
function SecureAcl([string]$Path,[bool]$Container,[string]$RunnerSid){$acl=if($Container){New-Object Security.AccessControl.DirectorySecurity}else{New-Object Security.AccessControl.FileSecurity};$acl.SetAccessRuleProtection($true,$false);foreach($sidText in @('S-1-5-18','S-1-5-32-544',$RunnerSid)){ $sid=New-Object Security.Principal.SecurityIdentifier($sidText);$inherit=if($Container){[Security.AccessControl.InheritanceFlags]'ContainerInherit, ObjectInherit'}else{[Security.AccessControl.InheritanceFlags]::None};$rule=New-Object Security.AccessControl.FileSystemAccessRule($sid,[Security.AccessControl.FileSystemRights]::FullControl,$inherit,[Security.AccessControl.PropagationFlags]::None,[Security.AccessControl.AccessControlType]::Allow);$acl.AddAccessRule($rule)};$acl.SetOwner((New-Object Security.Principal.SecurityIdentifier($RunnerSid)));Set-Acl -LiteralPath $Path -AclObject $acl}
function WriteJob($paths,[string]$State,$extra=@{}){ $old=if(Test-Path -LiteralPath $paths.job){Get-Content -LiteralPath $paths.job -Raw|ConvertFrom-Json}else{$null};$value=[ordered]@{};if($old){foreach($p in $old.PSObject.Properties){$value[$p.Name]=$p.Value}};$value.schema_version=$schema;$value.run_identifier=$RunId;$value.state=$State;$value.updated_utc=(Get-Date).ToUniversalTime().ToString('o');$value.evidence_root=$EvidenceRoot;$value.runner_identity=Identity;$value.runner_script_path=$PSCommandPath;$value.runner_script_sha256=Hash $PSCommandPath;$value.terminal_path=$terminal;$value.paths=$paths;if(!$value.created_utc){$value.created_utc=$value.updated_utc};foreach($key in $extra.Keys){$value[$key]=$extra[$key]};AtomicJson $paths.job $value;return $value }
function RequireSecureRoot(){
 if(!(Test-Path -LiteralPath $EvidenceRoot -PathType Container)){throw 'missing evidence root'}
 $volume=Get-Volume -DriveLetter ([IO.Path]::GetPathRoot($EvidenceRoot).TrimEnd(':','\'))
 if($volume.HealthStatus -ne 'Healthy'){throw 'unhealthy evidence volume'}
 if($volume.SizeRemaining -lt 5GB){throw 'insufficient evidence free space'}
 AssertSecureAcl $EvidenceRoot $true;$tree=@($EvidenceRoot)+@(Get-ChildItem -LiteralPath $EvidenceRoot -Recurse -Force|ForEach-Object{$_.FullName});foreach($path in @($tree|Select-Object -Skip 1)){AssertSecureAcl $path}
 return [ordered]@{volume_health=[string]$volume.HealthStatus;free_bytes=[int64]$volume.SizeRemaining;acl=(AclView $EvidenceRoot);secured_path_count=$tree.Count;identity=Identity}
}
function NoTerminal(){if(Get-Process terminal64,metatester64 -ErrorAction SilentlyContinue){throw 'conflicting terminal_or_tester'}}
function NoCampaignJob(){ $jobs=Join-Path $EvidenceRoot 'jobs';if(!(Test-Path -LiteralPath $jobs)){return};foreach($path in @(Get-ChildItem -LiteralPath $jobs -Filter '*.json' -File -ErrorAction Stop)){ $job=Get-Content -LiteralPath $path.FullName -Raw|ConvertFrom-Json;if($job.state-eq'packaging'){throw 'conflicting persistent campaign job'};if(@('launch-requested','launched','bootstrap-confirmed','running') -contains $job.state -and ((BoundProcess $job.bootstrap_binding)-or(BoundProcess $job.workload_binding))){throw 'conflicting persistent campaign job'} } }
function RequireWorker([string]$Incoming){$p=Join-Path $Incoming 'phase-0a-h\windows\execute-ten-strategy-packet.ps1';if(!(Test-Path -LiteralPath $p)){throw 'missing bound packet worker'};return $p}
function RequireCachePreflightWorker([string]$Incoming){$p=Join-Path $Incoming 'phase-0a-h\windows\execute-phase2-offline-cache-probe.ps1';$resolver=Join-Path $Incoming 'phase-0a-h\windows\resolve-phase2-mt5-server-scope.ps1';if(!(Test-Path -LiteralPath $p) -or !(Test-Path -LiteralPath $resolver)){throw 'missing bound server-scoped cache preflight role'};return $p}
function ProcessView([int]$ProcessId){
 $process=Get-CimInstance Win32_Process -Filter ('ProcessId='+$ProcessId) -ErrorAction SilentlyContinue
 if(!$process){return $null}
 [ordered]@{pid=[int]$process.ProcessId;parent_pid=[int]$process.ParentProcessId;start_time_utc=if($process.CreationDate){([datetime]$process.CreationDate).ToUniversalTime().ToString('o')}else{$null};executable_path=[string]$process.ExecutablePath;command_line=[string]$process.CommandLine;session_id=[int]$process.SessionId}
}
function BoundProcess($Binding){
 if(!$Binding -or !$Binding.pid -or !$Binding.start_time_utc -or !$Binding.executable_path -or !$Binding.command_line -or !$Binding.run_identifier){return $false}
 $actual=ProcessView ([int]$Binding.pid);if(!$actual){return $false}
 return ($actual.start_time_utc-eq[string]$Binding.start_time_utc -and $actual.executable_path-eq[string]$Binding.executable_path -and $actual.command_line-eq[string]$Binding.command_line -and $actual.command_line-like('*'+[string]$Binding.run_identifier+'*'))
}
function FailureDirectory($paths){if(Test-Path -LiteralPath $paths.running){return $paths.running};if(Test-Path -LiteralPath $paths.complete){return $paths.complete};throw 'missing failure evidence directory'}
function WriteLifecycleFailure($paths,[string]$ExceptionType,[string]$Message,[int]$ExitCode,[string]$LastStep,[string]$Position=$null){
 $directory=FailureDirectory $paths;$stdoutHash=if(Test-Path -LiteralPath $paths.stdout){Hash $paths.stdout}else{$null};$stderrHash=if(Test-Path -LiteralPath $paths.stderr){Hash $paths.stderr}else{$null};$job=if(Test-Path -LiteralPath $paths.job){Get-Content -LiteralPath $paths.job -Raw|ConvertFrom-Json}else{$null}
 $value=[ordered]@{schema_version='nora.phase2_detached_lifecycle_failure_v1';run_identifier=$RunId;exception_type=$ExceptionType;message=$Message;position_or_stack=if($Position){$Position.Substring(0,[Math]::Min(4096,$Position.Length))}else{$null};exit_code=$ExitCode;last_completed_lifecycle_step=$LastStep;stdout_path=$paths.stdout;stdout_sha256=$stdoutHash;stderr_path=$paths.stderr;stderr_sha256=$stderrHash;worker_pid=if($job.workload_binding){$job.workload_binding.pid}elseif($job.bootstrap_binding){$job.bootstrap_binding.pid}else{$null};worker_start_time_utc=if($job.workload_binding){$job.workload_binding.start_time_utc}elseif($job.bootstrap_binding){$job.bootstrap_binding.start_time_utc}else{$null};worker_script_path=if($job.workload_script_path){$job.workload_script_path}else{$WorkloadPath};worker_script_sha256=if($job.workload_sha256){$job.workload_sha256}else{$WorkloadSha256};configuration_path=if($job.configuration_path){$job.configuration_path}else{$ConfigurationPath};configuration_sha256=if($job.configuration_sha256){$job.configuration_sha256}else{$ConfigurationSha256};failure_utc=(Get-Date).ToUniversalTime().ToString('o')}
 AtomicJson (Join-Path $directory 'lifecycle-failure.json') $value;return $value
}
function ValidateRunnerParse(){
 $tokens=$null;$errors=$null;[Management.Automation.Language.Parser]::ParseFile($PSCommandPath,[ref]$tokens,[ref]$errors)|Out-Null;if(@($errors).Count){throw ('runner parse validation failed: '+$errors[0].Message)}
}
function LaunchDetached($paths,[string]$Worker,[string[]]$WorkerArguments,[string]$ConfigPath,[string]$Kind){
 ValidateRunnerParse;if(!(Test-Path -LiteralPath $Worker -PathType Leaf)){throw 'missing detached workload'}
 $workerHash=Hash $Worker;$configHash=Hash $ConfigPath;$identity=Identity
 $envelope=[ordered]@{schema_version='nora.phase2_detached_launch_envelope_v1';run_identifier=$RunId;kind=$Kind;launcher=[ordered]@{path=$PSCommandPath;sha256=Hash $PSCommandPath;identity=$identity};workload_script_path=$Worker;workload_script_sha256=$workerHash;workload_argument_tokens=@($WorkerArguments);configuration_path=$ConfigPath;configuration_sha256=$configHash;working_directory=$paths.running;stdout_path=$paths.stdout;stderr_path=$paths.stderr;evidence_root=$EvidenceRoot;created_utc=(Get-Date).ToUniversalTime().ToString('o')}
 $envelopePath=Join-Path $EvidenceRoot ('jobs\'+$RunId+'.envelope.json');AtomicJson $envelopePath $envelope;$envelopeHash=Hash $envelopePath
 WriteJob $paths 'launch-requested' @{lifecycle_schema_version='nora.phase2_detached_lifecycle_v2';launch_kind=$Kind;workload_script_path=$Worker;workload_sha256=$workerHash;configuration_path=$ConfigPath;configuration_sha256=$configHash;launch_envelope_path=$envelopePath;launch_envelope_sha256=$envelopeHash}|Out-Null
 $runner=$PSCommandPath;$command='powershell.exe -NoLogo -NoProfile -NonInteractive -ExecutionPolicy Bypass -File "'+$runner+'" -Mode detached-bootstrap -RunId "'+$RunId+'" -EnvelopePath "'+$envelopePath+'" -LauncherName "'+$identity.name+'" -LauncherSid "'+$identity.sid+'" -WorkloadPath "'+$Worker+'" -WorkloadSha256 "'+$workerHash+'" -ConfigurationPath "'+$ConfigPath+'" -ConfigurationSha256 "'+$configHash+'" -WorkingDirectory "'+$paths.running+'" -StdoutPath "'+$paths.stdout+'" -StderrPath "'+$paths.stderr+'" -EvidenceRoot "'+$EvidenceRoot+'"'
 try{$created=Invoke-CimMethod -ClassName Win32_Process -MethodName Create -Arguments @{CommandLine=$command} -ErrorAction Stop}catch{$failure=WriteLifecycleFailure $paths $_.Exception.GetType().FullName $_.Exception.Message 70 'launch-requested' $_.ScriptStackTrace;WriteJob $paths 'failed' @{failure_record_sha256=Hash (Join-Path (FailureDirectory $paths) 'lifecycle-failure.json')}|Out-Null;throw}
 if($created.ReturnValue-ne0){$failure=WriteLifecycleFailure $paths 'Win32ProcessCreateFailure' ('Win32_Process.Create returned '+$created.ReturnValue) ([int]$created.ReturnValue) 'launch-requested';WriteJob $paths 'failed' @{failure_record_sha256=Hash (Join-Path (FailureDirectory $paths) 'lifecycle-failure.json')}|Out-Null;throw 'detached process creation failed'}
 $view=$null;for($i=0;$i-lt40-and!$view;$i++){Start-Sleep -Milliseconds 50;$view=ProcessView ([int]$created.ProcessId)}
 if(!$view){$failure=WriteLifecycleFailure $paths 'BootstrapExitedBeforeBinding' 'bootstrap process exited before launcher binding was recorded' 71 'launch-requested';WriteJob $paths 'failed' @{failure_record_sha256=Hash (Join-Path (FailureDirectory $paths) 'lifecycle-failure.json')}|Out-Null;throw 'bootstrap exited before binding'}
 $binding=[ordered]@{};foreach($key in $view.Keys){$binding[$key]=$view[$key]};$binding.run_identifier=$RunId;$binding.envelope_sha256=$envelopeHash
 WriteJob $paths 'launched' @{bootstrap_binding=$binding;worker_pid=$binding.pid;worker_started_utc=$binding.start_time_utc;worker_executable_path=$binding.executable_path;worker_command_line=$binding.command_line}|Out-Null;AtomicJson (Join-Path $paths.running 'launch-binding.json') $binding
 [ordered]@{run_identifier=$RunId;state='launched';bootstrap_binding=$binding;launch_envelope_path=$envelopePath;launch_envelope_sha256=$envelopeHash}|ConvertTo-Json -Depth 12 -Compress
}

switch($Mode){
 'detached-workload' {
   $p=Paths;$envelope=Get-Content -LiteralPath $EnvelopePath -Raw|ConvertFrom-Json;if($envelope.run_identifier-ne$RunId -or $envelope.schema_version-ne'nora.phase2_detached_launch_envelope_v1'){throw 'detached workload envelope identity'};if((Hash $EnvelopePath)-ne$envelope.configuration_sha256 -and $EnvelopePath-eq$envelope.configuration_path){throw 'recursive workload configuration'};if((Hash $envelope.workload_script_path)-ne$envelope.workload_script_sha256){throw 'detached workload hash mismatch'}
   $resultPath=Join-Path (FailureDirectory $p) 'workload-result.json';try{$tokens=@($envelope.workload_argument_tokens);if($tokens.Count%2-ne0){throw 'workload argument token count must be even'};$splat=@{};for($i=0;$i-lt$tokens.Count;$i+=2){$name=[string]$tokens[$i];if($name-notmatch'^-[A-Za-z][A-Za-z0-9]*$'){throw 'invalid workload parameter token'};$key=$name.Substring(1);if($splat.ContainsKey($key)){throw 'duplicate workload parameter token'};$splat[$key]=$tokens[$i+1]};& $envelope.workload_script_path @splat;if(!$?){throw 'detached workload returned failure'};AtomicJson $resultPath ([ordered]@{schema_version='nora.phase2_detached_workload_result_v1';run_identifier=$RunId;state='completed';exit_code=0;completed_utc=(Get-Date).ToUniversalTime().ToString('o')})}catch{$detail=[ordered]@{schema_version='nora.phase2_detached_workload_failure_detail_v1';run_identifier=$RunId;exception_type=$_.Exception.GetType().FullName;message=$_.Exception.Message;position_or_stack=if($_.ScriptStackTrace){$_.ScriptStackTrace.Substring(0,[Math]::Min(4096,$_.ScriptStackTrace.Length))}elseif($_.InvocationInfo.PositionMessage){$_.InvocationInfo.PositionMessage.Substring(0,[Math]::Min(4096,$_.InvocationInfo.PositionMessage.Length))}else{$null};failed_utc=(Get-Date).ToUniversalTime().ToString('o')};AtomicJson (Join-Path (FailureDirectory $p) 'workload-failure-detail.json') $detail;AtomicJson $resultPath ([ordered]@{schema_version='nora.phase2_detached_workload_result_v1';run_identifier=$RunId;state='failed';exit_code=1;failed_utc=(Get-Date).ToUniversalTime().ToString('o')});[Console]::Error.WriteLine($detail.message);exit 1}
   exit 0
 }
 'detached-bootstrap' {
   $p=Paths;$bootstrapPath=Join-Path $p.running 'bootstrap.json'
   $self=ProcessView $PID;$bootstrap=[ordered]@{schema_version='nora.phase2_detached_bootstrap_v1';lifecycle_schema_version='nora.phase2_detached_lifecycle_v2';run_identifier=$RunId;worker_script_path=$PSCommandPath;worker_script_sha256=Hash $PSCommandPath;workload_script_path=$WorkloadPath;workload_script_sha256=$WorkloadSha256;launcher_identity=[ordered]@{name=$LauncherName;sid=$LauncherSid};bootstrap_utc=(Get-Date).ToUniversalTime().ToString('o');windows_identity=Identity;pid=$PID;parent_pid=$self.parent_pid;process_start_time_utc=$self.start_time_utc;executable_path=$self.executable_path;command_line=$self.command_line;working_directory=(Get-Location).Path;requested_working_directory=$WorkingDirectory;received_arguments=[ordered]@{mode=$Mode;run_identifier=$RunId;envelope_path=$EnvelopePath;evidence_root=$EvidenceRoot;workload_path=$WorkloadPath;workload_sha256=$WorkloadSha256;configuration_path=$ConfigurationPath;configuration_sha256=$ConfigurationSha256;working_directory=$WorkingDirectory;stdout_path=$StdoutPath;stderr_path=$StderrPath};configuration_path=$ConfigurationPath;configuration_sha256=$ConfigurationSha256;stdout_path=$StdoutPath;stderr_path=$StderrPath;environment=@(Get-ChildItem Env:|Sort-Object Name|ForEach-Object{[ordered]@{name=$_.Name;value=$_.Value}})};AtomicJson $bootstrapPath $bootstrap
   try{
    if((Hash $PSCommandPath)-ne(Hash $PSCommandPath)){throw 'unreachable bootstrap self hash'};if((Hash $ConfigurationPath)-ne$ConfigurationSha256){throw 'bootstrap configuration hash mismatch'};if((Hash $WorkloadPath)-ne$WorkloadSha256){throw 'bootstrap workload hash mismatch'}
    $envelope=Get-Content -LiteralPath $EnvelopePath -Raw|ConvertFrom-Json;if($envelope.schema_version-ne'nora.phase2_detached_launch_envelope_v1' -or $envelope.run_identifier-ne$RunId -or $envelope.workload_script_path-ne$WorkloadPath -or $envelope.workload_script_sha256-ne$WorkloadSha256 -or $envelope.configuration_path-ne$ConfigurationPath -or $envelope.configuration_sha256-ne$ConfigurationSha256){throw 'bootstrap envelope binding mismatch'}
    $launchBindingPath=Join-Path $p.running 'launch-binding.json';for($i=0;$i-lt200-and!(Test-Path -LiteralPath $launchBindingPath);$i++){Start-Sleep -Milliseconds 50};if(!(Test-Path -LiteralPath $launchBindingPath)){throw 'launcher binding publication timeout'};$launchBinding=Get-Content -LiteralPath $launchBindingPath -Raw|ConvertFrom-Json;if($launchBinding.pid-ne$PID -or $launchBinding.start_time_utc-ne$self.start_time_utc -or $launchBinding.executable_path-ne$self.executable_path -or $launchBinding.command_line-ne$self.command_line -or $launchBinding.run_identifier-ne$RunId){throw 'bootstrap process binding mismatch'}
    Set-Location -LiteralPath $WorkingDirectory;WriteJob $p 'bootstrap-confirmed' @{bootstrap_record_path=$bootstrapPath;bootstrap_record_sha256=Hash $bootstrapPath;bootstrap_binding=$launchBinding;last_completed_lifecycle_step='bootstrap-confirmed'}|Out-Null
    $runner=$PSCommandPath;$arguments=@('-NoLogo','-NoProfile','-NonInteractive','-ExecutionPolicy','Bypass','-File',$runner,'-Mode','detached-workload','-RunId',$RunId,'-EnvelopePath',$EnvelopePath,'-EvidenceRoot',$EvidenceRoot);$child=Start-Process -FilePath powershell.exe -ArgumentList $arguments -WorkingDirectory $WorkingDirectory -RedirectStandardOutput $StdoutPath -RedirectStandardError $StderrPath -PassThru
    $childView=$null;for($i=0;$i-lt40-and!$childView;$i++){Start-Sleep -Milliseconds 25;$childView=ProcessView $child.Id};if(!$childView){throw 'workload exited before binding'};$workloadBinding=[ordered]@{};foreach($key in $childView.Keys){$workloadBinding[$key]=$childView[$key]};$workloadBinding.run_identifier=$RunId;$workloadBinding.envelope_sha256=Hash $EnvelopePath;AtomicJson (Join-Path $p.running 'workload-binding.json') $workloadBinding;WriteJob $p 'running' @{workload_binding=$workloadBinding;last_completed_lifecycle_step='running'}|Out-Null
    $child.WaitForExit();$child.Refresh();$observedExitCode=[int]$child.ExitCode;$workloadResultPath=Join-Path (FailureDirectory $p) 'workload-result.json';$workloadResult=if(Test-Path -LiteralPath $workloadResultPath){Get-Content -LiteralPath $workloadResultPath -Raw|ConvertFrom-Json}else{$null};$exitCode=if(!$workloadResult){75}elseif($workloadResult.state-eq'failed'){[int]$workloadResult.exit_code}elseif($workloadResult.state-eq'completed' -and $observedExitCode-eq0){0}else{76};if($exitCode-ne0){$detailPath=Join-Path (FailureDirectory $p) 'workload-failure-detail.json';$detail=if(Test-Path -LiteralPath $detailPath){Get-Content -LiteralPath $detailPath -Raw|ConvertFrom-Json}else{$null};$type=if($detail){[string]$detail.exception_type}elseif(!$workloadResult){'DetachedWorkloadResultMissing'}else{'DetachedWorkloadNonzeroExit'};$message=if($detail){[string]$detail.message}elseif(!$workloadResult){'detached workload exited without a durable result'}else{'detached workload result or observed exit was nonzero'};$position=if($detail){[string]$detail.position_or_stack}else{$null};WriteLifecycleFailure $p $type $message $exitCode 'running' $position|Out-Null;WriteJob $p 'failed' @{last_completed_lifecycle_step='running';exit_code=$exitCode;observed_process_exit_code=$observedExitCode;failure_record_sha256=Hash (Join-Path (FailureDirectory $p) 'lifecycle-failure.json')}|Out-Null;exit $exitCode}
    Set-Location -LiteralPath $EvidenceRoot;if(Test-Path -LiteralPath $p.running){if(Test-Path -LiteralPath $p.complete){throw 'contradictory completion directories'};Move-Item -LiteralPath $p.running -Destination $p.complete}elseif(!(Test-Path -LiteralPath $p.complete)){throw 'workload removed durable run directory'}
    WriteJob $p 'completed' @{last_completed_lifecycle_step='completed';exit_code=0;completed_utc=(Get-Date).ToUniversalTime().ToString('o')}|Out-Null;exit 0
   }catch{$type=$_.Exception.GetType().FullName;$message=$_.Exception.Message;$position=if($_.ScriptStackTrace){$_.ScriptStackTrace}else{$_.InvocationInfo.PositionMessage};try{WriteLifecycleFailure $p $type $message 72 'bootstrap-confirmed' $position|Out-Null;WriteJob $p 'failed' @{last_completed_lifecycle_step='bootstrap-confirmed';exit_code=72;failure_record_sha256=Hash (Join-Path (FailureDirectory $p) 'lifecycle-failure.json')}|Out-Null}catch{};exit 72}
 }
 'canary-prepare' {
   $root=RequireSecureRoot;NoTerminal;$p=Paths;foreach($path in @($p.incoming,$p.running,$p.complete,$p.returned,$p.job)){if(Test-Path -LiteralPath $path){throw 'duplicate or stale run identity'}};foreach($dir in @($EvidenceRoot,(Join-Path $EvidenceRoot 'incoming'),(Join-Path $EvidenceRoot 'runs'),(Join-Path $EvidenceRoot 'jobs'),(Join-Path $EvidenceRoot 'logs'),(Join-Path $EvidenceRoot 'canary-packages'))){New-Item -ItemType Directory -Path $dir -Force|Out-Null};New-Item -ItemType Directory -Path $p.incoming|Out-Null;New-Item -ItemType Directory -Path $p.running|Out-Null;WriteJob $p 'prepared' @{run_kind='detached_lifecycle_canary';canary_kind=$CanaryKind;prepared_root=$root;run_directory=$p.running}|ConvertTo-Json -Depth 12 -Compress
 }
 'canary-launch' {
   $root=RequireSecureRoot;NoTerminal;$p=Paths;$job=Get-Content -LiteralPath $p.job -Raw|ConvertFrom-Json;if($job.state-ne'prepared' -or $job.run_kind-ne'detached_lifecycle_canary' -or $job.canary_kind-ne$CanaryKind){throw 'canary launch state'};$worker=Join-Path $p.incoming 'phase-0a-h\windows\phase2-detached-canary.ps1';$config=Join-Path $EvidenceRoot ('jobs\'+$RunId+'.config.json');AtomicJson $config ([ordered]@{schema_version='nora.phase2_detached_canary_config_v1';run_identifier=$RunId;canary_kind=$CanaryKind;run_directory=$p.running;created_utc=(Get-Date).ToUniversalTime().ToString('o')});$arguments=if($CanaryKind-eq'parameter-failure'){@('-RunId',$RunId,'-RunDirectory',$p.running,'-UnexpectedParameter','true')}else{@('-RunId',$RunId,'-RunDirectory',$p.running,'-CanaryKind',$CanaryKind)};LaunchDetached $p $worker $arguments $config 'detached_lifecycle_canary'
